(function(){(document.querySelector(`.video-container`)||document.querySelector(`.dashboard-container`)||document.getElementById(`btn-generate-meet-link`)||document.querySelector(`.room-header`))&&(console.log(`[OxiqAI] Web Dashboard Bridge active.`),document.documentElement.setAttribute(`data-oxiqai-extension-active`,`true`),window.addEventListener(`OXIQ_TRIGGER_AUTO_MEET`,e=>{let t=e.detail?.platform||`google_meet`;console.log(`[OxiqAI Bridge] Triggering meet creation for platform:`,t),chrome.runtime.sendMessage({action:`CREATE_MEET_AUTO`,platform:t},e=>{if(chrome.runtime.lastError){console.error(`[OxiqAI Bridge] Extension communication failed:`,chrome.runtime.lastError.message),window.dispatchEvent(new CustomEvent(`OXIQ_AUTO_MEET_FAILED`,{detail:{error:`Please reload extension and webpage.`}}));return}e&&e.success&&e.link?(console.log(`[OxiqAI Bridge] Meeting link generated successfully:`,e.link),window.dispatchEvent(new CustomEvent(`OXIQ_AUTO_MEET_SUCCESS`,{detail:{link:e.link}}))):(console.error(`[OxiqAI Bridge] Meeting link generation failed:`,e?.error||`Unknown error`),window.dispatchEvent(new CustomEvent(`OXIQ_AUTO_MEET_FAILED`,{detail:{error:e?.error||`Link generation failed.`}})))})}));})()